/**
 * Get OS Icon component by platform name
 */
export const getOSIcon = (platform) => {
  switch (platform?.toLowerCase()) {
    case 'windows':
      return WindowsIcon;
    case 'linux':
      return LinuxIcon;
    case 'macos':
    case 'darwin':
      return AppleIcon;
    default:
      return null;
  }
};
 
export default {
  WindowsIcon,
  LinuxIcon,
  AppleIcon,
  getOSIcon,
};
 